// ============================================================
// CONFIG v3 — 12-post IG grid cycle
// ============================================================
const config = {
  brand: 'Agenius 3D',
  brandVoice: 'maker-focused, technical but accessible, enthusiastic about 3D printing and AI design',
  hashtags: {
    base: '#agenius3d #3dprinting #3dprinted #maker #makerspace #3ddesign',
    tips: '#3dprintingtips #3dprinthacks #makertips #fdm #printinglife',
    models: '#3dmodel #3dart #cad #productdesign #prototyping',
    design: '#productdesign #caddesign #prototyping #designprocess #3dmodeling',
    art: '#3dart #digitalart #generativeart #3dprintedart #makersmovement',
    tech: '#3dprintingtech #fdmprinting #slicersettings #printquality #filament'
  },
  kieModel: 'nano-banana-2',
  kieAspectRatio: '1:1',
  kieResolution: '2K',
  kieOutputFormat: 'jpg',
  maxPollAttempts: 30,
  pollIntervalSeconds: 5,
  telegramChatId: 'YOUR_TELEGRAM_CHAT_ID',
  airtableBaseId: 'YOUR_AIRTABLE_BASE_ID',
  airtableTableId: 'YOUR_AIRTABLE_TABLE_ID',
  metaPageId: 'YOUR_META_PAGE_ID',
  metaIgUserId: 'YOUR_META_IG_USER_ID',
  contentTypes: ['tips', 'models', 'design', 'tech', 'art']
};

// ============================================================
// 12-POST IG GRID CYCLE
// Row pattern: Models x3, Tip/Tech/Tip, Art x3, Design x3
// ============================================================
const cycle = [
  'models', 'models', 'models',   // Row 1
  'tips',   'tech',   'tips',     // Row 2
  'art',    'art',    'art',      // Row 3
  'design', 'design', 'design'    // Row 4
];

// Get last cycle position from Airtable fetch
const records = $input.first().json.records || [];
let lastPosition = -1;
if (records.length > 0 && records[0].fields && records[0].fields['Cycle Position'] != null) {
  lastPosition = parseInt(records[0].fields['Cycle Position'], 10);
}

const position = (lastPosition + 1) % 12;
const contentType = cycle[position];

config.contentType = contentType;
config.cyclePosition = position;
config.cycleRow = Math.floor(position / 3);
config.runTimestamp = new Date().toISOString();

return [{ json: config }];

// Parse Tips GPT response and standardize output
const response = $input.first().json;
const config = $('Config').first().json;

let parsed;
try {
  let content = response.content[0].text;
  // Strip markdown code fences if present
  content = content.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/,'').trim();
  parsed = JSON.parse(content);
} catch(e) {
  throw new Error('Failed to parse Tips GPT response: ' + e.message);
}

return [{
  json: {
    contentType: 'tips',
    contentSubtype: parsed.tipTopic || 'general',
    imagePrompt: parsed.imagePrompt || 'Infographic-style flat lay of 3D printing tools and filament spools on a clean workshop surface, bright natural light, technical aesthetic',
    caption: parsed.caption || '',
    elevenLabsScript: parsed.elevenLabsScript || parsed.tipContent || '',
    postTitle: parsed.tipTitle || '3D Printing Tip',
    config
  }
}];

// Parse Models GPT response and standardize output
const response = $input.first().json;
const config = $('Config').first().json;

let parsed;
try {
  let content = response.content[0].text;
  // Strip markdown code fences if present
  content = content.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/,'').trim();
  parsed = JSON.parse(content);
} catch(e) {
  throw new Error('Failed to parse Models GPT response: ' + e.message);
}

return [{
  json: {
    contentType: 'models',
    contentSubtype: parsed.modelName || 'showcase',
    imagePrompt: parsed.imagePrompt || 'Hero product shot of an intricate 3D printed object on a dark workshop workbench, dramatic side rim lighting, shallow depth of field, maker aesthetic',
    caption: parsed.caption || '',
    elevenLabsScript: parsed.elevenLabsScript || parsed.modelDescription || '',
    postTitle: parsed.modelName || '3D Model Showcase',
    config
  }
}];

// Parse Tech GPT response and standardize output
const response = $input.first().json;
const config = $('Config').first().json;

let parsed;
try {
  let content = response.content[0].text;
  // Strip markdown code fences if present
  content = content.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/,'').trim();
  parsed = JSON.parse(content);
} catch(e) {
  throw new Error('Failed to parse Tech GPT response: ' + e.message);
}

return [{
  json: {
    contentType: 'tech',
    contentSubtype: parsed.techTopic || 'slicer settings',
    imagePrompt: parsed.imagePrompt || 'Extreme close-up macro photography of 3D printer nozzle extruding filament, dramatic side lighting, shallow depth of field, technical and precise aesthetic',
    caption: parsed.caption || '',
    elevenLabsScript: parsed.elevenLabsScript || parsed.techContent || '',
    postTitle: parsed.techTitle || '3D Printing Tech Deep Dive',
    config
  }
}];

// Merge all branch outputs into unified format for KIE.ai
// This node receives output from whichever branch ran
const input = $input.first().json;
const config = input.config;

return [{
  json: {
    contentType: input.contentType,
    contentSubtype: input.contentSubtype || '',
    imagePrompt: input.imagePrompt,
    caption: input.caption,
    elevenLabsScript: input.elevenLabsScript,
    postTitle: input.postTitle || input.contentType,
    sourceUrl: input.sourceUrl || '',
    // Pass all config fields forward
    brand: config.brand,
    kieModel: config.kieModel,
    kieAspectRatio: config.kieAspectRatio,
    kieResolution: config.kieResolution,
    kieOutputFormat: config.kieOutputFormat,
    maxPollAttempts: config.maxPollAttempts,
    telegramChatId: config.telegramChatId,
    airtableBaseId: config.airtableBaseId,
    airtableTableId: config.airtableTableId,
    metaPageId: config.metaPageId,
    metaIgUserId: config.metaIgUserId,
    runTimestamp: config.runTimestamp
  }
}];

const item = $input.first().json;
const state = item.data?.state || 'pending';
const taskId = $('KIE Create').first().json.data?.taskId || '';
const pollCount = (item._pollCount || 0) + 1;
// Get unified data from Merge Branch Output
const cfg = $('Merge Branch Output').first().json;
if (state === 'success') {
  let imageUrl = '';
  try {
    const resultJson = JSON.parse(item.data.resultJson);
    imageUrl = resultJson.resultUrls?.[0] || '';
  } catch(e) { imageUrl = 'PARSE_ERROR: ' + e.message; }
  return [{ json: { ...cfg, generatedImageUrl: imageUrl, taskId, kieState: 'success', _pollCount: pollCount } }];
} else if (state === 'fail' || pollCount >= 30) {
  return [{ json: { ...cfg, taskId, kieState: 'fail', _pollCount: pollCount,
    reason: state === 'fail' ? 'KIE task failed' : 'Max polls (' + pollCount + ') reached' } }];
} else {
  return [{ json: { ...item, ...cfg, taskId, kieState: 'polling', _pollCount: pollCount } }];
}

