const cfg = $('KIE Check').first().json;
const config = $('Config').first().json;
const igId = $('IG Publish').first().json.id || '';

return [{
  json: {
    'Content Title': (cfg.contentType || 'Content') + ' - ' + new Date().toLocaleDateString(),
    'Type': cfg.contentType ? cfg.contentType.charAt(0).toUpperCase() + cfg.contentType.slice(1) : 'Photo',
    'Script/Caption': cfg.caption || '',
    'Status': 'Published',
    'Post Date': new Date().toISOString().split('T')[0],
    'Output Type': 'photo',
    'Generation Source': 'live_v3',
    'Image Prompt': cfg.imagePrompt || '',
    'KIE Task ID': cfg.taskId || '',
    'IG Post ID': String(igId),
    'Source Image': cfg.generatedImageUrl || '',
    'Cycle Position': config.cyclePosition
  }
}];

// Parse Product Design GPT response and standardize output
const response = $input.first().json;
const config = $('Config').first().json;

let parsed;
try {
  let content = response.content[0].text;
  // Strip markdown code fences if present
  content = content.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/,'').trim();
  parsed = JSON.parse(content);
} catch(e) {
  throw new Error('Failed to parse Design GPT response: ' + e.message);
}

return [{
  json: {
    contentType: 'design',
    contentSubtype: parsed.designTopic || 'product design',
    imagePrompt: parsed.imagePrompt || 'Product design workspace with CAD software, 3D printed prototypes, technical drawings, warm lighting, professional photography',
    caption: parsed.caption || '',
    elevenLabsScript: parsed.elevenLabsScript || parsed.designDescription || '',
    postTitle: parsed.designTitle || 'Product Design',
    config
  }
}];

// Parse Art GPT response and standardize output
const response = $input.first().json;
const config = $('Config').first().json;

let parsed;
try {
  let content = response.content[0].text;
  // Strip markdown code fences if present
  content = content.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/,'').trim();
  parsed = JSON.parse(content);
} catch(e) {
  throw new Error('Failed to parse Art GPT response: ' + e.message);
}

return [{
  json: {
    contentType: 'art',
    contentSubtype: parsed.artTopic || '3d art',
    imagePrompt: parsed.imagePrompt || 'Stunning 3D printed art sculpture with dramatic gallery lighting, artistic composition, vibrant colors, professional photography',
    caption: parsed.caption || '',
    elevenLabsScript: parsed.elevenLabsScript || parsed.artDescription || '',
    postTitle: parsed.artTitle || '3D Printed Art',
    config
  }
}];

// Build dedup context from past Airtable records
const records = $input.first().json.records || [];
const config = $('Config').first().json;

const pastTopics = records.map(r => {
  const title = r.fields['Content Title'] || '';
  const prompt = (r.fields['Image Prompt'] || '').substring(0, 120);
  return `- ${title} (prompt: ${prompt}...)`;
}).join('\n');

return [{
  json: {
    ...config,
    pastTopics: pastTopics || 'No previous posts found — this is the first post of this type.',
    pastTopicCount: records.length
  }
}];

